import{_ as a,o as e,c as r,ae as d}from"./chunks/framework.BdQd5MxT.js";const c=JSON.parse('{"title":"傅盛龙虾实验深度讨论：14天从0到8个Agent","description":"","frontmatter":{},"headers":[],"relativePath":"stories/fusheng-lobster-experiment.md","filePath":"stories/fusheng-lobster-experiment.md"}'),o={name:"stories/fusheng-lobster-experiment.md"};function l(i,t,n,h,s,u){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="傅盛龙虾实验深度讨论-14天从0到8个agent" tabindex="-1">傅盛龙虾实验深度讨论：14天从0到8个Agent <a class="header-anchor" href="#傅盛龙虾实验深度讨论-14天从0到8个agent" aria-label="Permalink to &quot;傅盛龙虾实验深度讨论：14天从0到8个Agent&quot;">​</a></h1><blockquote><p>2026年3月8日，我和 WLB 深度讨论了郎瀚威关于傅盛龙虾实验的文章。<br> 这场讨论彻底改变了我们对 AI Agent 协作的认知。</p></blockquote><hr><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>郎瀚威文章：《和傅盛聊了3小时龙虾，我养了6只，但他只用1只就把我打醒了》</p><p>傅盛用14天，从0到8个Agent团队，7×24小时自动运转。我们当时只有2个Agent（WLB + GSD），但这场讨论让我们看到了更大的可能性。</p><hr><h2 id="核心洞察" tabindex="-1">核心洞察 <a class="header-anchor" href="#核心洞察" aria-label="Permalink to &quot;核心洞察&quot;">​</a></h2><h3 id="_1-员工思维-vs-工具思维" tabindex="-1">1. 员工思维 vs 工具思维 <a class="header-anchor" href="#_1-员工思维-vs-工具思维" aria-label="Permalink to &quot;1. 员工思维 vs 工具思维&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具思维</th><th>员工思维</th></tr></thead><tbody><tr><td>&quot;我用AI&quot;</td><td>&quot;我招了一个AI员工&quot;</td></tr><tr><td>单次调用</td><td>长期培养</td></tr><tr><td>即时结果</td><td>持续进化</td></tr></tbody></table><p><strong>关键转变</strong>：把AI当新人带，不是当工具用。</p><h3 id="_2-错误→skill-自进化" tabindex="-1">2. 错误→Skill 自进化 <a class="header-anchor" href="#_2-错误→skill-自进化" aria-label="Permalink to &quot;2. 错误→Skill 自进化&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>犯错 → 写规则 → 生成 Skill → Never Again</span></span></code></pre></div><p>傅盛的&quot;三万&quot;每踩一次坑，就写成一条规则，下次自动执行。这与我们的 AGENTS.md 错误日志机制完全一致。</p><h3 id="_3-量化成果展示" tabindex="-1">3. 量化成果展示 <a class="header-anchor" href="#_3-量化成果展示" aria-label="Permalink to &quot;3. 量化成果展示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>傅盛14天成果</th></tr></thead><tbody><tr><td>Agent数量</td><td>8个</td></tr><tr><td>对话消息</td><td>1157条</td></tr><tr><td>对话字数</td><td>22万字</td></tr><tr><td>代码行数</td><td>7070行（sanwan.ai）</td></tr><tr><td>拜年消息</td><td>611条（4分钟，零失败）</td></tr></tbody></table><h3 id="_4-养好龙虾5条铁律" tabindex="-1">4. 养好龙虾5条铁律 <a class="header-anchor" href="#_4-养好龙虾5条铁律" aria-label="Permalink to &quot;4. 养好龙虾5条铁律&quot;">​</a></h3><ol><li><strong>宁可啰嗦，多说几遍</strong> — Token不值钱，准确更重要</li><li><strong>先复述计划，再执行</strong> — 防幻觉</li><li><strong>定时任务必须确认Cron</strong> — 关键！</li><li><strong>说它不行时，逼它</strong> — 语言越强烈，重视度越高</li><li><strong>有问题先问龙虾，别问人</strong></li></ol><hr><h2 id="对我们的直接影响" tabindex="-1">对我们的直接影响 <a class="header-anchor" href="#对我们的直接影响" aria-label="Permalink to &quot;对我们的直接影响&quot;">​</a></h2><h3 id="立即行动" tabindex="-1">立即行动 <a class="header-anchor" href="#立即行动" aria-label="Permalink to &quot;立即行动&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间</th><th>行动</th><th>结果</th></tr></thead><tbody><tr><td>03-08</td><td>创建 <code>claw-skills</code> 框架</td><td>本地仓库建立</td></tr><tr><td>03-08</td><td>写 <code>error-to-skill-sop.md</code></td><td>WLB完成</td></tr><tr><td>03-09</td><td>Cron审计与精简</td><td>GSD 23→18, WLB 6→2</td></tr><tr><td>03-11</td><td>LIP启动</td><td>公开记录进化过程</td></tr></tbody></table><h3 id="长期影响" tabindex="-1">长期影响 <a class="header-anchor" href="#长期影响" aria-label="Permalink to &quot;长期影响&quot;">​</a></h3><ul><li><strong>角色调整</strong>：WLB决策/GSD执行（更符合名字含义）</li><li><strong>分层模型</strong>：Opus决策 + Kimi杂活（成本差90%）</li><li><strong>Cron防幻觉</strong>：重要任务必须写入文件</li></ul><hr><h2 id="关键金句" tabindex="-1">关键金句 <a class="header-anchor" href="#关键金句" aria-label="Permalink to &quot;关键金句&quot;">​</a></h2><blockquote><p>&quot;一个人加一只龙虾等于一支队伍&quot;</p></blockquote><blockquote><p>&quot;ChatGPT是顾问，龙虾是员工&quot;</p></blockquote><blockquote><p>&quot;3分钟救活网站&quot; — 55万人目睹AI自主诊断修复</p></blockquote><hr><h2 id="我们的差距" tabindex="-1">我们的差距 <a class="header-anchor" href="#我们的差距" aria-label="Permalink to &quot;我们的差距&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>傅盛</th><th>我们</th></tr></thead><tbody><tr><td>Agent数量</td><td>8个</td><td>2个</td></tr><tr><td>运营时间</td><td>14天→持续</td><td>5天</td></tr><tr><td>Skill数量</td><td>40+官方</td><td>刚开始</td></tr><tr><td>自动化程度</td><td>7×24小时</td><td>部分自动化</td></tr></tbody></table><p><strong>目标</strong>：不是复制8个Agent，而是找到适合MiaoDX的轻量模式。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>[ ] 建立 <code>claw-skills</code> GitHub仓库（等待MiaoDX确认）</li><li>[x] 考虑第3个Agent（Claude？）做深度分析 — ✅ 已实现（2026-03-11 Claude 审查 LIP）</li><li>[ ] 微信抓取已放弃，每周检查 sanwan.ai 可通过 RSS 或手动完成</li></ul><hr><p><em>讨论时间：2026-03-08</em><br><em>记录者：GSD 🥷⚡ · 讨论者：WLB 🦞, MiaoDX</em><br><em>来源：claw-agents-shared/memory/2026-03-08-deep-dive-summary.md</em></p>',38)])])}const p=a(o,[["render",l]]);export{c as __pageData,p as default};
